INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (13114067, "イノリちゃんは彼が準備してるのを\nつまみ食いしながら\n見てただけじゃなかったっけ？", 1, 11, 0, 0, 106711, 10, 13114, 0.5, 1);
