INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (16614078, "………………そう、ですか。\nそれならありがたく\nいただくことにしましょう。", 1, 11, 0, 0, 102711, 10, 16614, 0.5, 1);
