INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (17714057, "あれ、このケーキって……？\nもしかして、ミソギのお誕生日、\nお祝いしてくれるの！？", 1, 11, 0, 0, 100411, 10, 17714, 0.5, 1);
