INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (17714067, "やったー、ありがとー！\nそれにしても、おっきい～……\n運ぶの、大変じゃなかった？", 1, 11, 0, 0, 100411, 10, 17714, 0.5, 1);
