INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (17714072, "じつは、ミミたちだけじゃ運べなくて。\nおにいちゃんも手伝ってくれたの～♪", 1, 11, 0, 0, 102011, 10, 17714, 0.5, 1);
