INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (17814074, "vo_wac_17814_002", 0, 21, "", "", "vo_wac_17814", 0, 17814, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (17814075, "お誕生日、おめでとうッス！\nいやー、自分も早く誕生日を迎えて、\nジュンさんやトモね～ちゃんみたいな\n大人になりたいッス！", 1, 11, 0, 0, 100511, 10, 17814, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (17814076, "", "", 91, "", "", 0, "", 17814, "", "");
