INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (17824055, "坊やに相談されたんだ、\nオマエの誕生日を祝いたいとな。\nオクトーの坊やは不在だが……\nワタシがいるのだ、退屈はさせんぞ☆", 1, 11, 0, 0, 107111, 10, 17824, 0.5, 1);
