INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (18814071, "こ、ここ、これはまさか～！？\nナナカちゃん生誕祭の準備！？\n……であってるよね？　単にケーキを\n食べたかっただけとかじゃないよね？", 1, 11, 0, 0, 101311, 10, 18814, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (18814072, "", "", 91, "", "", 0, "", 18814, "", "");
