INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (18814085, "vo_wac_18814_003", 0, 21, "", "", "vo_wac_18814", 0, 18814, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (18814086, "シグルドからも助言を得ている。\nナナカ生誕を祝すのにふさわしい、\n伝説級の品々を用意してあるぞ？\n限定魔法少女グッズの詰め合わせだ！", 1, 11, 0, 0, 100911, 10, 18814, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (18814087, "", "", 91, "", "", 0, "", 18814, "", "");
