INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (18814089, "wac_birthday_talk_smile", "", 3, 0.2, "", 101311, 1, 18814, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (18814090, "vo_wac_18814_004", 0, 21, "", "", "vo_wac_18814", 0, 18814, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (18814091, "なんという僥倖ッ！\nみなさま、感謝いたしますぞ～！！\n期待に応えてこれからも、ぐうかわ\n魔法少女として邁進していくことを……", 1, 11, 0, 0, 101311, 10, 18814, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (18814092, "", "", 91, "", "", 0, "", 18814, "", "");
