INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (18814094, "wac_birthday_eriko_talk_sad", "", 3, 0.2, "", 102711, 1, 18814, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (18814095, "vo_wac_18814_005", 0, 21, "", "", "vo_wac_18814", 0, 18814, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (18814096, "ところで。\nどうしてナナカさんが欲しがっている\n限定品を、あなた様が正確に把握して\nいらっしゃったのでしょう……？", 1, 11, 0, 0, 102711, 10, 18814, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (18814097, "", "", 91, "", "", 0, "", 18814, "", "");
