INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (19214058, "わあー、これって私の\n誕生日ケーキですか？\nとってもおいしそう！", 1, 11, 0, 0, 101111, 10, 19214, 0.5, 1);
