INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (19214063, "おいしいに決まってるよ～！\nみんなでリノちゃんのために\n腕によりをかけたんだから！", 1, 11, 0, 0, 104911, 10, 19214, 0.5, 1);
