INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (19414063, "騎士クンとレイちゃん、\nみんなで手作りしたの♪\nお店で買った方がおいしいかもって、\nちょっと迷ったりもしたんだけど……", 1, 11, 0, 0, 100211, 10, 19414, 0.5, 1);
