INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (19814071, "このおいしそうなケーキは……ハッ！？\nワタシの命を狙う、アクダイカンの\n仕組んだトラップでショウか？", 1, 11, 0, 0, 103011, 10, 19814, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (19814072, "", "", 91, "", "", 0, "", 19814, "", "");
