INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (19814086, "誕生日にそんなことされて喜ぶのは、\nクウカさんだけだと思います……", 1, 11, 0, 0, 105511, 10, 19814, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (19814087, "", "", 91, "", "", 0, "", 19814, "", "");
