INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (19814091, "ワタシの誕生日ケーキ！？\nそれは大変、ゴブレイしマシタ♪\n本来であればセップクものですが、\n腹よりケーキを切りまショウ♪", 1, 11, 0, 0, 103011, 10, 19814, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (19814092, "", "", 91, "", "", 0, "", 19814, "", "");
