INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (19814096, "ちなみに、このケーキは美しいボクと\nギルドの仲間たち、それといつもの\nこの人で選んだんだ。主にボクの\n顔を思い浮かべつつ味わってよね♪", 1, 11, 0, 0, 100811, 10, 19814, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (19814097, "", "", 91, "", "", 0, "", 19814, "", "");
