INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (20014090, "あの、キャル……\n喜んでるところ、悪いんだけど……\nその、材料の方は、魔物の……\nペコリーヌさんが、どうしてもって……", 1, 11, 0, 0, 106411, 10, 20014, 0.5, 1);
