INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (21714052, "vo_wac_21714_001", 0, 21, "", "", "vo_wac_21714", 0, 21714, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (21714053, "クレジッタさん、\nお誕生日おめでとうございます！\n今日はたくさんお祝いしましょうね☆\nケーキ、わたしの手作りなんですよ～！", 1, 11, 0, 0, 105811, 10, 21714, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (21714054, "", "", 91, "", "", 0, "", 21714, "", "");
