INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (21714062, "食べるのが非常～～～に\nもったいなくはございますが……！\nこのクレジッタ・キャッシュ！\n心していただきますわ～！！", 1, 11, 0, 0, 118011, 10, 21714, 0.5, 1);
