INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (22014073, "よーし、いっぱい踊るさー♪\nほらほら、カスミもこっち来て、\n一緒に踊りでお祝いしよーさー？", 1, 11, 0, 0, 101711, 10, 22014, 0.5, 1);
