INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (22014078, "ま、待ちたまえ！\n私は君たちみたいに乱暴な\n誕生日祝いをするつもりは……\nふ、振り回さないで～！？", 1, 11, 0, 0, 101411, 10, 22014, 0.5, 1);
