INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (22714056, "年に一度のイノリ様の誕生日が\nきやがったですよ！\nファミリー総出で景気よく、これ以上\nないほど盛大にお祝いしやがれです！", 1, 11, 0, 0, 106611, 10, 22714, 0.5, 1);
