INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (22714061, "……イノリちゃん？\nみんなイノリちゃんのためにケーキを\n用意して集まってくれてるんだから、\nまずはなんて言うのが正しいのかな～？", 1, 11, 0, 0, 106711, 10, 22714, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (22714062, "", "", 91, "", "", 0, "", 22714, "", "");
