INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (22714066, "えっ、あっ、それは……！？\nここ、この度はあたしのお誕生日を\nお祝いしてくれやがりまして、まことに\nありがとうございますです！", 1, 11, 0, 0, 106611, 10, 22714, 0.5, 1);
