INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (23214078, "アヤネちゃん、それは内緒に……！\nうぅ、お料理中も結構ドジしちゃって。\nお嬢様の大切な日の準備なのに、\nすみません……", 1, 11, 0, 0, 102511, 10, 23214, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (23214079, "", "", 91, "", "", 0, "", 23214, "", "");
