INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (23214083, "なに言ってるのよ、そこまでして\n用意してくれたってことでしょう？\nあんたも、来てくれてありがとう。\nずっと、みんなと仲良くしてあげてね？", 1, 11, 0, 0, 102811, 10, 23214, 0.5, 1);
