INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (23814077, "wac_birthday_talk_doya", "", 3, 0.2, "", 105311, 1, 23814, "", "");
