INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (23814084, "どうもありがとう♪\nそれにしても素晴らしいケーキだね、\nボクのために用意してくれたの？", 1, 11, 0, 0, 100811, 10, 23814, 0.5, 1);
