INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (25214056, "わあ、素敵なケーキだね。\nお姉ちゃんのために\n弟くんが用意してくれたの？\n愛を感じちゃうなあ。", 1, 11, 0, 0, 104911, 10, 25214, 0.5, 1);
