INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (25214066, "シズルちゃんへの感謝の\n気持ちを込めてね。\nって、お邪魔じゃなければ\nいいんだけど。", 1, 11, 0, 0, 106811, 10, 25214, 0.5, 1);
