INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (25214071, "そんなことないよ～。\nありがとうね、マスター、リノちゃん。\n弟くんにはこのあとたっぷりと\n付き合ってもらうから大丈夫だよ。ね？", 1, 11, 0, 0, 104911, 10, 25214, 0.5, 1);
