INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (25314070, "今日は、こんな盛大なお祝いを\n開いてくれるなんてね。\n個人としても、団長としても、\nすごくうれしいよ。", 1, 11, 0, 0, 104711, 10, 25314, 0.5, 1);
