INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (25314075, "当然だな☆\nこのクリスティーナが全て段取りを\nつけたのだ、満足できないはずがない！", 1, 11, 0, 0, 107111, 10, 25314, 0.5, 1);
