INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (25314080, "……その段取りを実行に移すために、\nボロ雑巾になるまで働いたのは\n自分たちなんスけど。", 1, 11, 0, 0, 100511, 10, 25314, 0.5, 1);
