INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (26214066, "wac_birthday_talk_smile", "", 3, 0.2, "", 103311, 1, 26214, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (26214067, "vo_wac_26214_001", 0, 21, "", "", "vo_wac_26214", 0, 26214, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (26214068, "そうだべ！\n誕生日おめでとう、シオシオ！\nこのケーキはシオシオの好きな\n牧場特製の食材も使って作ったべや！", 1, 11, 0, 0, 103311, 10, 26214, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (26214069, "", "", 91, "", "", 0, "", 26214, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (26214070, "wac_birthday_idle_smile", "", 3, 0.2, "", 103311, 1, 26214, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (26214071, "wac_birthday_talk_kyapi", "", 3, 0.2, "", 105211, 1, 26214, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (26214072, "vo_wac_26214_002", 0, 21, "", "", "vo_wac_26214", 0, 26214, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (26214073, "私もだけど、彼とリンちゃんも準備を\nがんばったのよ♪\nふふっ、シオリちゃんのために～って\n張り切ってたのよね？", 1, 11, 0, 0, 105211, 10, 26214, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (26214074, "", "", 91, "", "", 26214073, "", 26214, "", "");
