INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (26214076, "wac_birthday_talk_normal", "", 3, 0.2, "", 102611, 1, 26214, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (26214077, "vo_wac_26214_003", 0, 21, "", "", "vo_wac_26214", 0, 26214, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (26214078, "そ、そりゃあしおりんのためだったら、\nあたしだって、がんばるよ。\nほんと、おめでとうしおりん。\nいつもありがとね。", 1, 11, 0, 0, 102611, 10, 26214, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (26214079, "", "", 91, "", "", 0, "", 26214, "", "");
