INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (26214082, "vo_wac_26214_004", 0, 21, "", "", "vo_wac_26214", 0, 26214, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (26214083, "リンちゃん……それにみんな、\n本当にありがとうございます。\nあなたも来てくれるなんて、\n私、とってもうれしいです。", 1, 11, 0, 0, 103811, 10, 26214, 0.5, 1);
