INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (26224083, "そ、そんなに急かさなくても……！\nというか助手くんも来てくれたのかい？\nわざわざ祝いに来てくれるなんて、\nその……うん、すごく、うれしいよ。", 1, 11, 0, 0, 101411, 10, 26224, 0.5, 1);
