INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (27814086, "wac_birthday_talk_smile", "", 3, 0.2, "", 100811, 1, 27814, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (27814087, "vo_wac_27814_004", 0, 21, "", "", "vo_wac_27814", 0, 27814, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (27814088, "うんうん、せっかくだから、\nみんなでおいしく頂こうじゃないか♪\nそれにかわいらしいボクが祝うんだから、\n最高の誕生日になるよ♪", 1, 11, 0, 0, 100811, 10, 27814, 0.5, 1);
