INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (28414071, "wac_birthday_talk_wish", "", 3, 0.2, "", 104711, 1, 28414, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (28414072, "vo_wac_28414_002", 0, 21, "", "", "vo_wac_28414", 0, 28414, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (28414073, "おめでとう、マツリちゃん。\n私たちだけではなく、\n少年も一緒に準備してくれたんだよ。", 1, 11, 0, 0, 104711, 10, 28414, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (28414074, "", "", 91, "", "", 28414073, "", 28414, "", "");
