INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (28414083, "うっ……クリスティーナおばさんは\n怖いけど……みんな、ありがとうッス！\nそれにあんたも祝ってくれるなんて、\n自分はすごく幸せ者ッスよー！", 1, 11, 0, 0, 100511, 10, 28414, 0.5, 1);
