INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (29014058, "これって私の誕生日ケーキだよね！？\nみんなで用意してくれたの！？\nもしかして愛情たっぷりの手作り！？\nかわいー！　美味しそうー！", 1, 11, 0, 0, 109211, 10, 29014, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (29014059, "", "", 91, "", "", 0, "", 29014, "", "");
