INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (29014063, "ふふっ、喜んでもらえて良かった……\nアンのそんな顔が見たくて……\nがんばってみたの。\n……ね、ルゥ？", 1, 11, 0, 0, 109411, 10, 29014, 0.5, 1);
