INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (29014068, "そうですよー！\nルゥは今回も大活躍だったんですよ！\n材料をぐるぐるかき混ぜたり、\nかき混ぜたり、かき混ぜたりしました！", 1, 11, 0, 0, 109311, 10, 29014, 0.5, 1);
