INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (30314065, "えっと、私の誕生日をお祝いしてくれて\nありがとう。こんなふうに、\n誰かにお祝いしてもらえるなんて\n思ってなかったわ。", 1, 11, 0, 0, 106411, 10, 30314, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (30314066, "", "", 91, "", "", 0, "", 30314, "", "");
