INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (30314069, "vo_wac_30314_001", 0, 21, "", "", "vo_wac_30314", 0, 30314, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (30314070, "お祝いするに決まってますよ～！\nシェフィちゃんは【美食殿】の大切な\n仲間なんですから♪", 1, 11, 0, 0, 105811, 10, 30314, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (30314071, "", "", 91, "", "", 0, "", 30314, "", "");
