INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (30314074, "vo_wac_30314_002", 0, 21, "", "", "vo_wac_30314", 0, 30314, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (30314075, "でも、たくさん迷惑をかけているし。\nこんなふうにお祝いをしてもらう\n資格なんて……私には……", 1, 11, 0, 0, 106411, 10, 30314, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (30314076, "", "", 91, "", "", 0, "", 30314, "", "");
