INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (30314079, "vo_wac_30314_003", 0, 21, "", "", "vo_wac_30314", 0, 30314, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (30314080, "そうよね～、迷惑かけまくりよね～？\nお腹が空いたらすぐ泣くし、目についた\n物はなんでも口に入れちゃうし。", 1, 11, 0, 0, 106011, 10, 30314, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (30314081, "", "", 91, "", "", 0, "", 30314, "", "");
