INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (30314085, "そ、それはまた別の話でしょう！？\n私が言いたいのは……！", 1, 11, 0, 0, 106411, 10, 30314, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (30314086, "", "", 91, "", "", 0, "", 30314, "", "");
