INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (30314090, "わかっております、シェフィさま。\nそれでも……お二人は、あなたを\n大切に想っているのです。\nもちろん、わたくしと主さまも。", 1, 11, 0, 0, 105911, 10, 30314, 0.5, 1);
