INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (30314095, "……うん。\n改めて、本当にありがとう。\n私、みんなと出会えてよかった。\n今日のこと……絶対、忘れないから♪", 1, 11, 0, 0, 106411, 10, 30314, 0.5, 1);
