INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (31114089, "wac_birthday_talk_doya", "", 3, 0.2, "", 104411, 1, 31114, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (31114090, "vo_wac_31114_004", 0, 21, "", "", "vo_wac_31114", 0, 31114, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (31114091, "これ、お主たち。\nシノブの誕生日じゃというのに、\nお返しの話題で盛り上がるでないわ。\nまったく、こやつらは……", 1, 11, 0, 0, 104411, 10, 31114, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (31114092, "", "", 91, "", "", 0, "", 31114, "", "");
