INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (31114094, "wac_birthday_talk_normal", "", 3, 0.2, "", 103111, 1, 31114, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (31114095, "vo_wac_31114_005", 0, 21, "", "", "vo_wac_31114", 0, 31114, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (31114096, "大丈夫ですよ、イリヤさん。\nいつも通りの、自由な雰囲気で\n祝ってもらう方が気も楽ですから。\nあなたも、きっとそうですよね？", 1, 11, 0, 0, 103111, 10, 31114, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (31114097, "", "", 91, "", "", 0, "", 31114, "", "");
