INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (31114100, "……ありがとうございます。\nわざわざ占ったりしませんが、\nこういう幸せな日々が、\nずっと続くことを願っています。", 1, 11, 0, 0, 103111, 10, 31114, 0.5, 1);
