INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (31314058, "ハッピー☆バースデー☆ハツネちゃん！\nおっきなケーキまでもらっちゃって、\n最高の誕生日だよ～きらーんっ☆", 1, 11, 0, 0, 101211, 10, 31314, 0.5, 1);
