INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (31314063, "うん、おめでとう～♪\nみんなでケーキも用意したから、\n楽しくお祝いしましょうね～\nほら、アオイちゃんも。", 1, 11, 0, 0, 101511, 10, 31314, 0.5, 1);
