INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (31314068, "お、おお、おめでとうございます！\n私のようなぼっちが、陽の者である\nハツネさんの誕生日をお祝いするのは、\n恐れ多い感じではあるんですが！", 1, 11, 0, 0, 104011, 10, 31314, 0.5, 1);
