INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (32114065, "えっとさー、その～……\n普段あんまりお仕事してないのに、\nこんな大げさにお祝いされると\n気まずいっていうか～……", 1, 11, 0, 0, 102611, 10, 32114, 0.5, 1);
