INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (32114070, "今さら気にするくらいなら、\n普段からしっかりやればいいのに。\n……なんてお小言はさておき、\nお誕生日おめでとう、リンちゃん♪", 1, 11, 0, 0, 105211, 10, 32114, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (32114071, "", "", 91, "", "", 0, "", 32114, "", "");
