INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (32114075, "変に遠慮しないでくださいね？\nみんな、リンちゃんのことを\nお祝いしたくて、張り切って\n準備したんですから。", 1, 11, 0, 0, 103811, 10, 32114, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (32114076, "", "", 91, "", "", 0, "", 32114, "", "");
