INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (32114085, "ほ、本当だべか！？\n苦労して誕生日パーティーを用意した\n甲斐があったべさ～……って、ん？\nちょっと待つべ、来年？", 1, 11, 0, 0, 103311, 10, 32114, 0.5, 1);
