INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (32314068, "えっ！？\nそ、それは、その～……\n大人のレディ向けジュースとかないの？\n苦いのも、別にダメじゃないけど！", 1, 11, 0, 0, 105011, 10, 32314, 0.5, 1);
