INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (32314073, "ふふっ、ちゃんとあるわよ♪\nこうやってオシャレなグラスに\nぶどうジュースを注げば……\nほら、大人っぽいでしょう？", 1, 11, 0, 0, 101811, 10, 32314, 0.5, 1);
