INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (33214058, "今日は、こんな素敵な誕生日ケーキを\n用意してくれてありがとう。\nその……すまない、なんだか\n照れくさくて、上手く話せないな。", 1, 11, 0, 0, 100311, 10, 33214, 0.5, 1);
