INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (33214063, "大丈夫だよ。\n今のレイちゃんの顔を見たら、\nすごく喜んでくれてるって\nちゃんと分かるから♪", 1, 11, 0, 0, 100211, 10, 33214, 0.5, 1);
