INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (34314094, "wac_birthday_talk_sad", "", 3, 0.2, "", 104411, 1, 34314, "", "");
