INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (34314096, "う～む。\n際限なくプリンを要求してくるのは、\nもう悪霊に片足を突っ込んで\nおらんかのう？", 1, 11, 0, 0, 104411, 10, 34314, 0.5, 1);
