INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (34414061, "wac_birthday_talk_normal", "", 3, 0.2, "", 104211, 1, 34414, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (34414062, "vo_wac_34414_001", 0, 21, "", "", "vo_wac_34414", 0, 34414, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (34414063, "楽しそうではありますが……\nよく考えたら、お祝いされる方が\n歌って踊るというのも\n不思議な話ではありますね。", 1, 11, 0, 0, 104211, 10, 34414, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (34414064, "", "", 91, "", "", 0, "", 34414, "", "");
