INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (34414073, "ツムギ、いいこと言うじゃない♪\nそれじゃあ感謝の気持ちを込めて……\nキミのためのバースデーライブ、\n開催しちゃおうかな♪", 1, 11, 0, 0, 102911, 10, 34414, 0.5, 1);
