INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (35514058, "わーい！　ルゥのケーキですぅ～～♪\nルゥ、みんなにお祝いしてもらえるの\n楽しみにしてたですよ！", 1, 11, 0, 0, 109311, 10, 35514, 0.5, 1);
