INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (35514063, "楽しみにしてもらえて良かった！\n今回はグレアと一緒に、\nルゥのために手作りしたからね！\n私が材料をぐるぐるかき混ぜて……", 1, 11, 0, 0, 109211, 10, 35514, 0.5, 1);
