INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (35814085, "……少年、見てごらん。\nあんなふうに言ってはいるけど、\nクリスちゃん、すごくうれしそうだよ。\n口元が緩みっぱなしだからね。", 1, 11, 0, 0, 104711, 10, 35814, 0.5, 1);
