INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (36914085, "ん？　何か特別な日だっただろうか？\n確かこの日がいいと言ったのは……\nキミだったか？", 1, 11, 0, 0, 100311, 10, 36914, 0.5, 1);
