INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (38014071, "wac_birthday_talk_smile", "", 3, 0.2, "", 103411, 1, 38014, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (38014072, "vo_wac_38014_002", 0, 21, "", "", "vo_wac_38014", 0, 38014, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (38014073, "あら、私も本なのよ。\n「猫でもわかる麦しゅわの歴史」って\n本だけど、これを読んで麦しゅわへの\n理解を深めてね♪", 1, 11, 0, 0, 103411, 10, 38014, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (38014074, "", "", 91, "", "", 0, "", 38014, "", "");
