INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (38214083, "wac_birthday_talk_smile", "", 3, 0.2, "", 105211, 1, 38214, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (38214084, "vo_wac_38214_004", 0, 21, "", "", "vo_wac_38214", 0, 38214, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (38214085, "そうそう。\n難しい顔するより、\nみんなで楽しくおいしくケーキを\n食べましょう♪", 1, 11, 0, 0, 105211, 10, 38214, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (38214086, "", "", 91, "", "", 0, "", 38214, "", "");
