INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (38214088, "wac_birthday_talk_smile", "", 3, 0.2, "", 103311, 1, 38214, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (38214089, "vo_wac_38214_005", 0, 21, "", "", "vo_wac_38214", 0, 38214, "", "");
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (38214090, "いや、みんなにきちんと\nギャグでお返ししてぇべ！　……あ！\nバースデーは、とばーすでー！\nさ、今年も飛ばしてくど！", 1, 11, 0, 0, 103311, 10, 38214, 0.5, 1);
