INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (39114063, "本当に、ありがとうございます……！\n私、このように誕生日を祝ってくれる\n友人に恵まれて、幸せ者です！", 1, 11, 0, 0, 103211, 10, 39114, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (39114064, "", "", 91, "", "", 0, "", 39114, "", "");
