INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (39114068, "当然のことをしたまでにゃ♪\nアキノとは【メルクリウス財団】の\n仲間として、一緒に苦労してきたにゃ。", 1, 11, 0, 0, 104611, 10, 39114, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (39114069, "", "", 91, "", "", 0, "", 39114, "", "");
