INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (39114078, "麦しゅわの助けも借りながら、\nみんなで協力して、\n全部乗り越えることができたもの！", 1, 11, 0, 0, 103411, 10, 39114, 0.5, 1);
INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (39114079, "", "", 91, "", "", 0, "", 39114, "", "");
