INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (39114083, "麦しゅわで心の痛みを和らげていたのは\nユカリさんだけですが、確かに、\n私たちは戦友と呼べるほどに\n深い絆で結ばれたのかもしれません。", 1, 11, 0, 0, 103211, 10, 39114, 0.5, 1);
