INSERT INTO `v1_2d071eb062d79ee89bedcbc44b0d9337e36590abc11934b624d0d62f404f7ea2` VALUES (39114087, "それでは私の誕生日に加えて、\n【メルクリウス財団】の友情が\n永遠に続くことを願い……乾杯ですわ！", 1, 11, 0, 0, 103211, 10, 39114, 0.5, 1);
